// 수동 수집은 즉시 통과
if (msg.topic === 'manual') return msg;

const now = Date.now();
const nextCollectAt = global.get('nextCollectAt') || 0;

if (now < nextCollectAt) {
    const remain = Math.round((nextCollectAt - now) / 1000);
    node.status({ fill: 'blue', shape: 'ring', text: '대기 (' + remain + '초 후)' });
    return null; // 스킵
}

// houseConfig에서 최소 intervalSeconds 읽기
const config = global.get('houseConfig');
const houses = config && config.houses ? config.houses : [];
let interval = 600; // 기본 10분
for (const h of houses) {
    const hi = (h.collection && h.collection.intervalSeconds) || 600;
    if (hi < interval) interval = hi;
}
if (interval < 10) interval = 10; // 최소 10초 보장

global.set('nextCollectAt', now + interval * 1000);
global.set('appliedIntervalSeconds', interval);
node.status({ fill: 'green', shape: 'dot', text: '수집 (' + interval + '초 주기)' });
return msg;

const SERVER_URL = env.get('SERVER_URL') || 'http://192.168.137.1:3000';
const FARM_ID = env.get('FARM_ID') || 'farm_0001';
const HOUSE_ID = env.get('HOUSE_ID') || 'house_0001';
const API_KEY = env.get('SENSOR_API_KEY') || 'smartfarm-sensor-key';

// operationMode가 아직 설정 안 된 경우 (재시작 직후)
// serverOnline도 체크하여 기본값 결정
const serverOnline = global.get('serverOnline');
const operationMode = global.get('operationMode') || (serverOnline === true ? 'online' : 'offline');

if (operationMode === 'online') {
    // 온라인: 서버에서 설정 가져오기
    msg.url = `${SERVER_URL}/api/config/farm/${FARM_ID}`;
    msg.method = 'GET';
    msg.headers = { 'Content-Type': 'application/json', 'x-api-key': API_KEY };
    node.status({ fill: 'blue', shape: 'dot', text: '온라인: 서버 config 요청' });
    return [msg, null, null]; // 출력1: HTTP Request
} else {
    // 오프라인: global 캐시 → SQLite 캐시
    const cachedConfig = global.get('houseConfig');
    if (cachedConfig) {
        msg.config = cachedConfig;
        node.status({ fill: 'yellow', shape: 'dot', text: '오프라인: global 캐시 사용' });
        return [null, msg, null]; // 출력2: 센서 수집으로
    } else {
        // SQLite config_cache에서 로드
        msg.topic = 'SELECT config_json FROM config_cache ORDER BY version DESC LIMIT 1';
        node.status({ fill: 'yellow', shape: 'ring', text: '오프라인: SQLite 캐시 조회' });
        return [null, null, msg]; // 출력3: SQLite 조회
    }
}

// 서버 응답 실패 → 캐시 폴백
if (msg.statusCode !== 200) {
    var cached = global.get('houseConfig');
    if (cached) {
        node.warn('⚠️ 서버 응답 실패 (status=' + msg.statusCode + '), 캐시 사용');
        msg.config = cached;
        return [msg, null, null];
    }
    node.error('❌ 서버 응답 실패, 캐시도 없음');
    return [null, null, null];
}

var response = msg.payload;
if (!response || !response.success) {
    node.error('설정 오류: ' + (response ? response.error || 'success=false' : 'payload null'));
    return [null, null, null];
}

var rawData = response.data;
var config;

// GET /api/config/farm/:farmId → data가 배열(하우스 목록)
if (Array.isArray(rawData)) {
    var FARM_ID = env.get('FARM_ID') || 'farm_0001';
    var enabledHouses = rawData.filter(function(h) { return h.enabled !== false; });
    var maxVersion = 0;
    rawData.forEach(function(h) {
        var v = h.configVersion || 0;
        if (v > maxVersion) maxVersion = v;
    });
    config = { farmId: FARM_ID, houses: enabledHouses, configVersion: maxVersion };
} else if (rawData && rawData.houses) {
    config = rawData;
} else {
    node.warn('⚠️ 예상 외 data 형식: ' + JSON.stringify(rawData).substring(0, 200));
    config = rawData;
}

if (!config || !config.houses) {
    node.error('❌ config 파싱 실패');
    var fb = global.get('houseConfig');
    if (fb) { msg.config = fb; return [msg, null, null]; }
    return [null, null, null];
}

// 항상 global 갱신 (최신 하우스 목록 반영)
global.set('houseConfig', config);
msg.config = config;

// configVersion 변경 감지 → ACK + SQLite 캐시 + 즉시 재수집
var cachedVersion = flow.get('lastConfigVersion') || 0;
if (config.configVersion > cachedVersion) {
    flow.set('lastConfigVersion', config.configVersion);
    node.warn('📋 설정 업데이트: v' + cachedVersion + ' → v' + config.configVersion + ' (' + config.houses.length + '개 하우스)');
    global.set('nextCollectAt', 0); // 즉시 재수집

    var cacheMsg = {
        topic: 'INSERT OR REPLACE INTO config_cache (id, farm_id, house_id, config_json, version, updated_at) VALUES (1, $1, $2, $3, $4, $5)',
        payload: [
            config.farmId || 'farm_0001',
            config.houses[0] ? config.houses[0].houseId : 'house_0001',
            JSON.stringify(config),
            config.configVersion || 1,
            new Date().toISOString()
        ]
    };

    var SERVER_URL = env.get('SERVER_URL') || 'http://192.168.137.1:3000';
    var API_KEY = env.get('SENSOR_API_KEY') || 'smartfarm-sensor-key';
    var ackMsg = {
        url: SERVER_URL + '/api/config/' + config.farmId + '/rpi-ack',
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'x-api-key': API_KEY },
        payload: {
            configVersion: config.configVersion,
            appliedAt: new Date().toISOString(),
            houses: config.houses.map(function(h) {
                return {
                    houseId: h.houseId,
                    intervalSeconds: (h.collection && h.collection.intervalSeconds) || 60
                };
            })
        }
    };
    node.warn('📤 RPi ACK 전송: v' + config.configVersion);
    return [msg, cacheMsg, ackMsg];
}

return [msg, null, null];

const rows = msg.payload || [];

if (rows.length > 0 && rows[0].config_json) {
    try {
        const config = JSON.parse(rows[0].config_json);
        global.set('houseConfig', config);
        msg.config = config;
        node.warn('📋 SQLite에서 config 복원 완료');
        node.status({ fill: 'green', shape: 'dot', text: 'SQLite config 복원' });
        return msg;
    } catch (e) {
        node.error('❌ config JSON 파싱 실패: ' + e.message);
    }
}

node.error('❌ SQLite config_cache도 비어있음 - 서버에 1회 접속 필요');
node.status({ fill: 'red', shape: 'dot', text: 'config 없음!' });
return null;

const config = msg.config || global.get('houseConfig');

if (!config) {
    node.error('❌ config 없음, 수집 중단');
    return null;
}

// 모든 하우스의 센서 수집 (멀티하우스 지원)
let housesToCollect = [];

if (config.houses && config.houses.length > 0) {
    housesToCollect = config.houses.filter(h => h.enabled !== false);
} else if (config.sensors) {
    // 단일 하우스 config (레거시 호환)
    housesToCollect = [{ houseId: config.houseId, sensors: config.sensors }];
}

if (housesToCollect.length === 0) {
    node.error('❌ 활성 하우스 없음');
    return null;
}

const farmId = config.farmId;
const messages = [];

for (const house of housesToCollect) {
    const sensors = house.sensors || [];
    const houseId = house.houseId;
    const enabledSensors = sensors.filter(s => s.enabled);

    if (enabledSensors.length === 0) {
        continue;
    }

    // 센서 데이터 읽기 (시뮬레이션 - 실제 GPIO 연결 시 여기를 수정)
    const sensorData = {};
    for (const sensor of enabledSensors) {
        try {
            let value;
            switch (sensor.sensorId) {
                case 'temp_0001':
                    value = parseFloat((Math.random() * 10 + 20).toFixed(1));
                    break;
                case 'humidity_0001':
                    value = parseFloat((Math.random() * 20 + 50).toFixed(1));
                    break;
                case 'co2_0001':
                    value = parseInt(Math.random() * 200 + 400);
                    break;
                default:
                    if (sensor.type === 'number') {
                        const min = sensor.min !== null ? sensor.min : 0;
                        const max = sensor.max !== null ? sensor.max : 100;
                        value = parseFloat((Math.random() * (max - min) + min).toFixed(sensor.precision || 1));
                    } else if (sensor.type === 'boolean') {
                        value = Math.random() > 0.5;
                    } else {
                        value = 'OK';
                    }
            }
            sensorData[sensor.sensorId] = value;
        } catch (e) {
            node.error('센서 읽기 실패: ' + sensor.sensorId + ' - ' + e.message);
            sensorData[sensor.sensorId] = null;
        }
    }

    messages.push({
        payload: {
            farmId: farmId,
            houseId: houseId,
            data: sensorData,
            timestamp: new Date().toISOString(),
            deviceInfo: {
                deviceId: env.get('DEVICE_ID') || 'rpi_0001',
                ip: '192.168.137.30',
                version: '2.0.0-offline'
            }
        }
    });
}

if (messages.length === 0) {
    node.warn('⚠️ 모든 하우스에 활성 센서 없음');
    return null;
}

const totalSensors = messages.reduce((sum, m) => sum + Object.keys(m.payload.data).length, 0);
node.warn('📡 ' + messages.length + '개 하우스, 총 ' + totalSensors + '개 센서 수집');
node.status({ fill: 'green', shape: 'dot', text: messages.length + '개 하우스 ' + totalSensors + '개 센서' });

return [messages];

const { farmId, houseId, data, timestamp } = msg.payload;
const ts = timestamp || new Date().toISOString();

// 센서 데이터 수집
const entries = Object.entries(data).filter(([k, v]) => v !== null && v !== undefined);

if (entries.length === 0) {
    node.warn('⚠️ 저장할 데이터 없음');
    return null;
}

// 위치 파라미터 쿼리로 개별 INSERT (센서별 msg 배열)
// node-red-node-sqlite msg.topic 모드: msg.payload 배열 + $N 파라미터 사용
const messages = entries.map(([sensorId, value]) => ({
    topic: 'INSERT INTO sensor_data (timestamp, farm_id, house_id, sensor_id, value, synced) VALUES ($1, $2, $3, $4, $5, 0)',
    payload: [ts, farmId, houseId, sensorId, value],
    _insertTimestamp: ts,
    _sensorCount: entries.length,
    _isLast: false,
    _originalPayload: msg.payload,
    _houseId: houseId
}));

// 마지막 메시지에 표시 (모드 분기용)
const srvOnline = global.get('serverOnline');
const opMode = global.get('operationMode') || (srvOnline === true ? 'online' : 'offline');
messages[messages.length - 1]._isLast = true;
messages[messages.length - 1]._operationMode = opMode;

node.warn('💾 SQLite INSERT: ' + houseId + ' ' + entries.length + '건');
return [messages];

// 마지막 INSERT 메시지만 처리 (나머지는 통과)
if (!msg._isLast) { return null; }

const serverOnline = global.get('serverOnline');
const mode = msg._operationMode || global.get('operationMode') || (serverOnline === true ? 'online' : 'offline');

// 자동화 평가용 메시지 (모드와 무관하게 항상 실행)
var evalMsg = null;
if (msg._originalPayload) {
    evalMsg = {
        sensorData: {
            farmId: msg._originalPayload.farmId,
            houseId: msg._originalPayload.houseId,
            data: msg._originalPayload.data
        }
    };
}

// 원본 payload 복원 (서버 전송용)
if (msg._originalPayload) { msg.payload = msg._originalPayload; }

if (mode === 'online') {
    const SERVER_URL = env.get('SERVER_URL') || 'http://192.168.137.1:3000';
    const API_KEY = env.get('SENSOR_API_KEY') || 'smartfarm-sensor-key';

    msg.url = SERVER_URL + '/api/sensors/collect';
    msg.method = 'POST';
    msg.headers = { 'Content-Type': 'application/json', 'x-api-key': API_KEY };
    msg.requestTimeout = 10000;

    node.status({ fill: 'green', shape: 'dot', text: '온라인: SQLite ✓ + 서버 전송' });
    return [msg, null, evalMsg];
} else {
    node.warn('📴 오프라인: SQLite만 저장 (synced=0)');
    node.status({ fill: 'yellow', shape: 'dot', text: '오프라인: SQLite ✓ (' + msg._sensorCount + '건)' });
    msg.payload = '오프라인 저장 완료: ' + msg._sensorCount + '건';
    return [null, msg, evalMsg];
}

if (msg.statusCode === 201 || msg.statusCode === 200) {
    node.warn('✅ 서버 전송 성공 → synced=1');

    const syncMsg = {
        topic: 'UPDATE sensor_data SET synced = 1 WHERE timestamp = $1 AND house_id = $2 AND synced = 0',
        payload: [msg._insertTimestamp, msg._houseId]
    };

    node.status({ fill: 'green', shape: 'dot', text: '서버 전송 ✓ + synced' });
    return [syncMsg, msg];
} else {
    node.warn('⚠️ 서버 전송 실패 (' + msg.statusCode + '): synced=0 유지');
    node.status({ fill: 'yellow', shape: 'ring', text: '전송 실패 (synced=0)' });
    return [null, msg];
}

var errMsg = msg.error ? msg.error.message : 'unknown';
node.warn('❌ SQLite 쓰기 에러: ' + errMsg);
node.status({fill:'red',shape:'dot',text:'SQLite 에러: ' + errMsg.substring(0,30)});

// 에러 카운트 (모니터링용)
var count = global.get('sqliteErrorCount') || 0;
global.set('sqliteErrorCount', count + 1);
global.set('lastSqliteError', {message: errMsg, timestamp: new Date().toISOString()});

return null;
